import{_ as a,o,c as s,ae as i}from"./chunks/framework.C7qU-Vik.js";const u=JSON.parse('{"title":"La Visión: El Claim del Namespace","description":"","frontmatter":{},"headers":[],"relativePath":"es/Namespace_Claim.md","filePath":"es/Namespace_Claim.md"}'),l={name:"es/Namespace_Claim.md"};function n(r,e,t,c,d,m){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="la-vision-el-claim-del-namespace" tabindex="-1">La Visión: El Claim del Namespace <a class="header-anchor" href="#la-vision-el-claim-del-namespace" aria-label="Permalink to &quot;La Visión: El Claim del Namespace&quot;">​</a></h1><p><strong>Estado actual:</strong> esta visión ya está parcialmente implementada en <code>monad.ai</code> v2.1.1. El claim del namespace sigue siendo la base de autoridad, pero ahora el runtime también anuncia monads en <code>_.mesh.monads</code>, resuelve claimants con <code>/.mesh/resolve</code>, y usa scoring para decidir qué monad debe responder cuando varios pueden servir el mismo namespace.</p><p>Ver también:</p><ul><li><code>docs/NRP/status.md</code></li><li><code>docs/NRP/scoring.md</code></li><li><code>docs/NRP/testing.md</code></li></ul><p>Lo que buscas es que el primer acto de tu kernel sea un <strong>Claim</strong>.</p><ol><li><strong>Local Claim:</strong> <code>me://local</code> (Yo soy este nodo).</li><li><strong>Network Claim:</strong> <code>me://username.cleaker.me</code> (Yo soy esta identidad en el ledger). Al hacer esto, tu <code>me://</code> ya no es un alias genérico; se convierte en una <strong>URL Soberana Determinista</strong>.</li></ol><hr><p>La Visión: El Claim del Namespace Lo que buscas es que el primer acto de tu kernel sea un <strong>Claim</strong>.</p><ol><li><strong>Local Claim:</strong> <code>me://local</code> (Yo soy este nodo).</li><li><strong>Network Claim:</strong> <code>me://username.cleaker.me</code> (Yo soy esta identidad en el ledger). Al hacer esto, tu <code>me://</code> ya no es un alias genérico; se convierte en una <strong>URL Soberana Determinista</strong>.</li></ol><hr><p><strong>B primero, luego C.</strong></p><p>El documento que escribimos ya es bueno como visión, pero ahora que tienes el análisis real del repo encima de la mesa, necesitamos anclar cada sección a lo que existe vs. lo que falta. Si saltamos directo a reescribir el doc sin el mapa, volvemos a escribir visión en lugar de protocolo.</p><p>Vamos al mapa.</p>',13)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
